import { useLanguage } from "../../context/language";
import { formatDate } from "../utils/date-utils";

interface MovieProfileProps {
  pictureUrl: string;
  releaseDate: string;
  ratingPosition?: number;
  title: string;
}


export function MovieProfile({
  pictureUrl,
  ratingPosition,
  releaseDate,
  title,
}: MovieProfileProps) {
  const { language } = useLanguage();
  return (
    <div className="bg-slate-800 rounded-lg flex flex-col text-center text-white font-semibold p-4 self-auto align-middle hover:bg-slate-700 hover:scale-125 transition-transform">
        <img
          className="mx-auto h-80 w-60 rounded-md"
          src={pictureUrl}
          alt={`Banner do Filme${title}`}
        />
        <p>{title}</p>
        <p className="font-nunito font-light">Release Date: {formatDate(language, releaseDate)}</p>
    </div>
  );
}
